// MARK: - Keychain Manager
class KeychainManager {
    private let service = "com.bankingapp.secure"
    private let encryptionKeyTag = "encryptionKey"
    
    func getEncryptionKey() throws -> SymmetricKey {
        if let keyData = try? retrieveKey(tag: encryptionKeyTag) {
            return SymmetricKey(data: keyData)
        } else {
            let key = SymmetricKey(size: .bits256)
            try storeKey(key.withUnsafeBytes { Data($0) }, tag: encryptionKeyTag)
