// MARK: - Transaction Validator
class TransactionValidator {
    static let shared = TransactionValidator()
    private let maxTransactionAmount: Decimal = 10000
    private let maxDailyTransactionAmount: Decimal = 50000
    
    private init() {}
    
    func validateTransaction(_ request: TransactionRequest, account: Account, dailyTotal: Decimal) throws {
        guard request.amount > 0 else {
            throw TransactionError.invalidAmount
        }
        
        guard request.amount <= maxTransactionAmount else {
            throw TransactionError.transactionLimitExceeded
        }
        
        guard dailyTotal + request.amount <= maxDailyTransactionAmount else {
            throw TransactionError.transactionLimitExceeded
        }
        
        if request.type == .debit || request.type == .transfer {
            guard account.balance >= request.amount else {
                throw TransactionError.insufficientFunds
            }
        }
    }
    
    func validatePin(_ pin: String) -> Bool {
        return pin.count >= 4 && pin.allSatisfy { $0.isNumber }
    }
}

