// MARK: - Transaction Manager
class TransactionManager {
    static let shared = TransactionManager()
    private let dataStore = SecureDataStore.shared
    private let validator = TransactionValidator.shared
    private var accounts: [Account] = []
    private var transactions: [Transaction] = []
    private let queue = DispatchQueue(label: "com.bankingapp.transactions", attributes: .concurrent)
    
    private init() {
        loadData()
    }
    
    private func loadData() {
        do {
            accounts = try dataStore.loadAccounts()
            transactions = try dataStore.loadTransactions()
        } catch {
            print("Error loading data: \(error)")
        }
    }
    
    func getAccounts() -> [Account] {
        return queue.sync { accounts }
    }
    
    func getAccount(by id: String) -> Account? {
        return queue.sync { accounts.first { $0.accountId == id } }
    }
    
    func getTransactions(for accountId: String) -> [Transaction] {
        return queue.sync {
            transactions.filter { $0.accountId == accountId }.sorted { $0.timestamp > $1.timestamp }
        }
    }
    
    func processTransaction(_ request: TransactionRequest, completion: @escaping (Result<Transaction, Error>) -> Void) {
        queue.async(flags: .barrier) {
            do {
                guard self.validator.validatePin(request.pin) else {
                    throw TransactionError.invalidPin
                }
                
                guard let accountIndex = self.accounts.firstIndex(where: { $0.accountId == request.fromAccountId }) else {
                    throw TransactionError.accountNotFound
                }
                
                let account = self.accounts[accountIndex]
                let dailyTotal = self.calculateDailyTotal(for: request.fromAccountId)
                
                try self.validator.validateTransaction(request, account: account, dailyTotal: dailyTotal)
                
                let transaction = Transaction(
                    transactionId: UUID().uuidString,
                    accountId: request.fromAccountId,
                    amount: request.amount,
                    type: request.type,
                    description: request.description,
                    timestamp: Date(),
                    status: .completed,
                    recipientAccountId: request.toAccountId
                )
                
                switch request.type {
                case .debit:
                    self.accounts[accountIndex].balance -= request.amount
                case .credit:
                    self.accounts[accountIndex].balance += request.amount
                case .transfer:
                    guard let toAccountId = request.toAccountId,
                          let toAccountIndex = self.accounts.firstIndex(where: { $0.accountId == toAccountId }) else {
                        throw TransactionError.accountNotFound
                    }
                    self.accounts[accountIndex].balance -= request.amount
                    self.accounts[toAccountIndex].balance += request.amount
                }
                
                self.transactions.append(transaction)
                
                try self.dataStore.saveAccounts(self.accounts)
                try self.dataStore.saveTransactions(self.transactions)
                
                DispatchQueue.main.async {
                    completion(.success(transaction))
                }
            } catch {
                DispatchQueue.main.async {
                    completion(.failure(error))
                }
            }
        }
    }
    
    private func calculateDailyTotal(for accountId: String) -> Decimal {
        let calendar = Calendar.current
        let today = calendar.startOfDay(for: Date())
        
        return transactions
            .filter { $0.accountId == accountId && calendar.startOfDay(for: $0.timestamp) == today }
            .filter { $0.type == .debit || $0.type == .transfer }
            .reduce(Decimal(0)) { $0 + $1.amount }
    }
    
    func addAccount(_ account: Account) throws {
        queue.async(flags: .barrier) {
            self.accounts.append(account)
            try? self.dataStore.saveAccounts(self.accounts)
        }
    }
}

