class AccountDetailViewController: UIViewController {
    private let account: Account
    private let tableView = UITableView()
    private let transactionManager = TransactionManager.shared
    private var transactions: [Transaction] = []
    
    init(account: Account) {
        self.account = account
        super.init(nibName: nil, bundle: nil)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        loadTransactions()
    }
    
    private func setupUI() {
        title = "Account Details"
        view.backgroundColor = .systemBackground
        
        let headerView = UIView(frame: CGRect(x: 0, y: 0, width: view.bounds.width, height: 100))
        let balanceLabel = UILabel(frame: headerView.bounds)
        balanceLabel.textAlignment = .center
        balanceLabel.font = .systemFont(ofSize: 32, weight: .bold)
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = account.currency
        balanceLabel.text = formatter.string(from: account.balance as NSDecimalNumber)
        headerView.addSubview(balanceLabel)
        
        tableView.frame = view.bounds
        tableView.autoresizingMask = [.flexibleWidth, .flexibleHeight]
        tableView.tableHeaderView = headerView
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(TransactionCell.self, forCellReuseIdentifier: "TransactionCell")
        view.addSubview(tableView)
        
        navigationItem.rightBarButtonItem = UIBarButtonItem(title: "New Transaction", style: .plain, target: self, action: #selector(newTransactionTapped))
    }
    
    private func loadTransactions() {
        transactions = transactionManager.getTransactions(for: account.accountId)
        tableView.reloadData()
    }
    
    @objc private func newTransactionTapped() {
        let alert = UIAlertController(title: "New Transaction", message: "Enter transaction details", preferredStyle: .alert)
        alert.addTextField { $0.placeholder = "Amount"; $0.keyboardType = .decimalPad }
        alert.addTextField { $0.placeholder = "Description" }
        alert.addTextField { $0.placeholder = "PIN"; $0.isSecureTextEntry = true; $0.keyboardType = .numberPad }
        
        alert.addAction(UIAlertAction(title: "Debit", style: .default) { [weak self] _ in
            self?.processTransaction(alert: alert, type: .debit)
        })
        alert.addAction(UIAlertAction(title: "Credit", style: .default) { [weak self] _ in
            self?.processTransaction(alert: alert, type: .credit)
        })
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    private func processTransaction(alert: UIAlertController, type: Transaction.TransactionType) {
        guard let amountString = alert.textFields?[0].text,
              let amount = Decimal(string: amountString),
              let description = alert.textFields?[1].text,
              let pin = alert.textFields?[2].text else { return }
        
        let request = TransactionRequest(
            fromAccountId: account.accountId,
            toAccountId: nil,
            amount: amount,
            type: type,
            description: description,
            pin: pin
        )
        
        transactionManager.processTransaction(request) { [weak self] result in
            switch result {
            case .success:
                self?.loadTransactions()
                self?.showAlert(title: "Success", message: "Transaction completed successfully")
            case .failure(let error):
                self?.showAlert(title: "Error", message: error.localizedDescription)
            }
        }
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

